def get_sales_summary_by_group(db_cursor, group_by_column: str) -> list:
    allowed_columns = {'product_category', 'region'}
    if group_by_column not in allowed_columns:
        raise ValueError(f"Invalid column for grouping: {group_by_column}. Allowed columns are: {allowed_columns}")

    query = f"SELECT {group_by_column}, SUM(sale_amount) AS total_sales FROM sales_orders GROUP BY {group_by_column}"
    db_cursor.execute(query)
    rows = db_cursor.fetchall()

    result = []
    for row in rows:
        result.append({group_by_column: row[0], 'total_sales': row[1]})
    return result
